The v7 `retry({ count, delay })` object form supersedes the deprecated `retryWhen`. Returning a `timer(ms)` from `delay` produces an exponential backoff purely by computing the delay off the attempt number.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface UserProfile {
  id: string;
  displayName: string;
}

declare function fetchProfile$(id: string): Observable<UserProfile>;

export function loadProfile$(id: string): Observable<UserProfile> {
  return fetchProfile$(id).pipe(
    retry({
      count: 4,
      delay: (_err: unknown, retryCount: number): Observable<number> =>
        timer(2 ** retryCount * 200),
    })
  );
}
```

If all four attempts fail, the original error is surfaced to the consumer unchanged.

In v7+, `retry({ count, delay })` encapsulates the same intent â€” bounded retries with a delay between each â€” without the awkward inner-error-observable dance of `retryWhen`.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface SyncResult {
  ok: boolean;
  syncedAt: number;
}

declare const source$: Observable<SyncResult>;

export const withFixedRetry$: Observable<SyncResult> = source$.pipe(
  retry({
    count: 3,
    delay: (): Observable<number> => timer(1000),
  })
);
```

`retryWhen` is deprecated because the nested observable gave consumers enough rope to accidentally resubscribe forever. The object form makes the retry budget explicit.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface HttpResponse {
  status: number;
  body: string;
}

declare function httpGet$(url: string): Observable<HttpResponse>;

export function fetchWithRetry$(url: string): Observable<HttpResponse> {
  return httpGet$(url).pipe(
    retry({
      count: 3,
      delay: (): Observable<number> => timer(500),
    })
  );
}
```

`count` replaces the manual scan-counter; `delay` replaces the inner pipe. The deprecated `retryWhen` operator is no longer required for the 99% case.

`retry(3)` retries up to three times but with zero delay â€” which typically just hammers the upstream and hits the same transient failure. Switch to the object form and supply an exponential `delay` callback.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface ApiResponse {
  data: string;
}

declare function callApi$(): Observable<ApiResponse>;

export const run$: Observable<ApiResponse> = callApi$().pipe(
  retry({
    count: 3,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(2 ** attempt * 300),
  })
);
```

First retry waits ~600 ms, then ~1200 ms, then ~2400 ms â€” enough to ride out brief blips without saturating the server.

Use `retry({ count, delay })` where `delay` is a callback returning an `Observable<number>` â€” typically `timer(ms)`.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Payload {
  value: number;
}

declare const source$: Observable<Payload>;

export const retried$: Observable<Payload> = source$.pipe(
  retry({
    count: 5,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(2 ** attempt * 100),
  })
);
```

The callback receives the error and the 1-indexed attempt number, so the delay doubles each time: 200, 400, 800, 1600, 3200 ms.

Fold the inner pipe into the `delay` callback on `retry`.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Ping {
  host: string;
  latencyMs: number;
}

declare const ping$: Observable<Ping>;

export const resilientPing$: Observable<Ping> = ping$.pipe(
  retry({
    count: Infinity,
    delay: (): Observable<number> => timer(1000),
  })
);
```

`count: Infinity` matches the original's "retry forever" semantics. For most real code you want a finite cap so the consumer sees failure eventually.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface StripeWebhookEvent {
  id: string;
  type: string;
  data: { object: Record<string, unknown> };
}

interface StripeAck {
  received: boolean;
}

interface HttpError {
  status: number;
  message: string;
}

declare function postWebhook$(evt: StripeWebhookEvent): Observable<StripeAck>;

function isRateLimited(err: unknown): err is HttpError {
  return typeof err === "object" && err !== null && (err as HttpError).status === 429;
}

export function deliverWebhook$(
  evt: StripeWebhookEvent
): Observable<StripeAck> {
  return postWebhook$(evt).pipe(
    retry({
      count: 6,
      delay: (err: unknown, attempt: number): Observable<number> =>
        isRateLimited(err)
          ? timer(2 ** attempt * 500)
          : throwError(() => err) as unknown as Observable<number>,
    })
  );
}
```

Only 429s trigger backoff; other errors propagate on the first failure.

```ts
import { Observable, MonoTypeOperatorFunction, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface ApiResult {
  ok: boolean;
}

declare function callApi$(): Observable<ApiResult>;

export function expBackoff<T>(count: number, baseMs: number): MonoTypeOperatorFunction<T> {
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      retry({
        count,
        delay: (_err: unknown, attempt: number): Observable<number> =>
          timer(2 ** attempt * baseMs),
      })
    );
}

export const run$: Observable<ApiResult> = callApi$().pipe(expBackoff(3, 200));
```

Hoisting the retry policy into a `MonoTypeOperatorFunction<T>` keeps it reusable across every HTTP pipeline without copy-pasting the config block.

`retry({ count, delay })` resubscribes to the source after each error. `count` caps the retries; `delay` is a function `(error, attempt) => Observable<unknown>` whose emission (or completion) triggers the resubscription. Returning `timer(ms)` turns it into a fixed or exponential wait.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Quote {
  symbol: string;
  price: number;
}

declare function fetchQuote$(sym: string): Observable<Quote>;

export function resilientQuote$(sym: string): Observable<Quote> {
  return fetchQuote$(sym).pipe(
    retry({
      count: 4,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(Math.min(2 ** attempt * 250, 5000)),
    })
  );
}
```

The `Math.min` caps the delay at 5 s so we don't back off past a useful horizon.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface WsFrame {
  opcode: number;
  payload: Uint8Array;
}

declare function openSocket$(url: string): Observable<WsFrame>;

const MAX_ATTEMPTS = 8;
const BASE_MS = 500;
const MAX_MS = 30_000;

export function connectSocket$(url: string): Observable<WsFrame> {
  return openSocket$(url).pipe(
    retry({
      count: MAX_ATTEMPTS,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(Math.min(2 ** attempt * BASE_MS, MAX_MS)),
    })
  );
}
```

Attempts 1..8 back off as 1 s, 2 s, 4 s, 8 s, 16 s, then cap at 30 s for the remaining attempts.

Full jitter spreads retries across the backoff window to avoid thundering-herd when many clients retry in lockstep.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface DdbItem {
  pk: string;
  sk: string;
  attrs: Record<string, string>;
}

declare function getItem$(pk: string, sk: string): Observable<DdbItem>;

function jitteredDelay(attempt: number): number {
  const ceiling: number = Math.min(2 ** attempt * 100, 10_000);
  return Math.floor(Math.random() * ceiling);
}

export function readItem$(pk: string, sk: string): Observable<DdbItem> {
  return getItem$(pk, sk).pipe(
    retry({
      count: 5,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(jitteredDelay(attempt)),
    })
  );
}
```

The jittered delay still grows exponentially on average but decorrelates retry attempts across concurrent clients.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Frame {
  ts: number;
  data: string;
}

declare const source$: Observable<Frame>;

export const migrated$: Observable<Frame> = source$.pipe(
  retry({
    count: 3,
    delay: (): Observable<number> => timer(1000),
  })
);
```

The `retryWhen` version threaded a counter through `mergeMap`'s index; `retry({ count })` handles that bookkeeping internally.

The number-only form works but retries instantly â€” the Twitter API will just hit you with another 429. Swap to the object form with a delay.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Tweet {
  id: string;
  text: string;
}

declare function fetchTweets$(): Observable<ReadonlyArray<Tweet>>;

export const tweets$: Observable<ReadonlyArray<Tweet>> = fetchTweets$().pipe(
  retry({
    count: 5,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(2 ** attempt * 1000),
  })
);
```

Now the 5 retries space out across roughly 2s, 4s, 8s, 16s, 32s.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface Hit {
  id: string;
  score: number;
}

interface HttpError {
  status: number;
}

declare function search$(q: string): Observable<ReadonlyArray<Hit>>;

function isServerError(err: unknown): err is HttpError {
  const e = err as HttpError;
  return typeof e?.status === "number" && e.status >= 500 && e.status < 600;
}

export const query$ = (q: string): Observable<ReadonlyArray<Hit>> =>
  search$(q).pipe(
    retry({
      count: 3,
      delay: (err: unknown, attempt: number): Observable<number> =>
        isServerError(err)
          ? timer(2 ** attempt * 500)
          : (throwError(() => err) as unknown as Observable<number>),
    })
  );
```

4xx errors like 400 or 401 fail immediately â€” retrying won't fix a malformed request or a bad token.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Record {
  id: string;
  value: string;
}

declare const source$: Observable<Record>;

export const bounded$: Observable<Record> = source$.pipe(
  retry({
    count: 3,
    delay: (): Observable<number> => timer(2000),
  })
);
```

The `delay` callback ignores its arguments and always returns `timer(2000)` â€” that's how you express a fixed-delay retry in v7.

An unbounded-count retry with a fixed delay â€” the `retry` object form expresses it directly.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Heartbeat {
  seq: number;
  ok: boolean;
}

declare const heartbeat$: Observable<Heartbeat>;

export const neverGiveUp$: Observable<Heartbeat> = heartbeat$.pipe(
  retry({
    count: Infinity,
    delay: (): Observable<number> => timer(200),
  })
);
```

Infinite retry is the right call for a health-check daemon but almost always wrong for a user-facing request â€” unbounded retries hide failures from the UI.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface EmailMessage {
  to: string;
  subject: string;
  html: string;
}

interface SendReceipt {
  messageId: string;
  acceptedAt: number;
}

declare function sendEmail$(msg: EmailMessage): Observable<SendReceipt>;

export function dispatchEmail$(msg: EmailMessage): Observable<SendReceipt> {
  return sendEmail$(msg).pipe(
    retry({
      count: 4,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(2 ** attempt * 400),
    })
  );
}
```

Four retries buy roughly 12 s of total wait; enough for a brief SendGrid outage without blocking the request-handler thread for too long.

```ts
import { MonoTypeOperatorFunction, Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Msg {
  text: string;
}

declare const source$: Observable<Msg>;

export function exponentialRetry<T>(
  count: number = 5,
  baseMs: number = 100
): MonoTypeOperatorFunction<T> {
  return (src$: Observable<T>): Observable<T> =>
    src$.pipe(
      retry({
        count,
        delay: (_err: unknown, attempt: number): Observable<number> =>
          timer(2 ** attempt * baseMs),
      })
    );
}

export const reliable$: Observable<Msg> = source$.pipe(exponentialRetry<Msg>(5, 100));
```

The helper is generic over `T` so it composes with any typed stream without repeating the type parameter.

`retry(n)` is the positional shorthand: up to `n` resubscriptions with zero delay. `retry({ count, delay })` supplements `count` with a `delay` callback so each retry waits for the returned observable to emit (typically `timer(ms)`). In v7+ the object form is the canonical way to express backoff â€” `retryWhen` is deprecated.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Job {
  id: string;
  result: string;
}

declare function runJob$(id: string): Observable<Job>;

export function runJobResilient$(id: string): Observable<Job> {
  return runJob$(id).pipe(
    retry({
      count: 3,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(2 ** attempt * 250),
    })
  );
}
```

The delay callback is re-evaluated per error, so you can make the delay depend on the error shape too.

```ts
import { MonoTypeOperatorFunction, Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface NetworkError extends Error {
  code: "ECONNRESET" | "ETIMEDOUT" | "ENOTFOUND";
}

function isNetworkError(err: unknown): err is NetworkError {
  const e = err as NetworkError;
  return e instanceof Error && typeof e.code === "string";
}

export function retryNetworkErrors<T>(): MonoTypeOperatorFunction<T> {
  return (src$: Observable<T>): Observable<T> =>
    src$.pipe(
      retry({
        count: 4,
        delay: (err: unknown, attempt: number): Observable<number> =>
          isNetworkError(err)
            ? timer(2 ** attempt * 300)
            : (throwError(() => err) as unknown as Observable<number>),
      })
    );
}
```

A `throwError` from the `delay` callback short-circuits the retry budget â€” the original error propagates to the consumer immediately.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface GqlRequest {
  query: string;
  variables: Record<string, unknown>;
}

interface GqlResponse<T> {
  data: T | null;
  errors?: ReadonlyArray<{ message: string }>;
}

interface ViewerData {
  viewer: { id: string; handle: string };
}

declare function gql$<T>(req: GqlRequest): Observable<GqlResponse<T>>;

export function viewer$(): Observable<GqlResponse<ViewerData>> {
  const req: GqlRequest = {
    query: "query Viewer { viewer { id handle } }",
    variables: {},
  };
  return gql$<ViewerData>(req).pipe(
    retry({
      count: 3,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(2 ** attempt * 200),
    })
  );
}
```

The retry is pure transport-level â€” application-level `errors[]` in the GraphQL response won't trigger a resubscription because they arrive as successful HTTP calls.

```ts
import { Observable, timer } from "rxjs";
import { retry, tap } from "rxjs/operators";

interface Record {
  id: string;
}

declare const source$: Observable<Record>;
declare function log(err: unknown): void;

export const fetch$: Observable<Record> = source$.pipe(
  tap({
    error: (err: unknown): void => log(err),
  }),
  retry({
    count: 4,
    delay: (): Observable<number> => timer(750),
  })
);
```

The side-effect log moves out of the retry-stream pipe into a `tap` observer on the main pipe â€” the error handler still fires per failed attempt because `retry` resubscribes the source, which re-runs the pipe.

The `.delay(500).take(2)` chain on the error observable is v4/RxJS-compat-Ext style. v7 replaces the whole thing with the object form.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Payload {
  id: number;
}

declare const source$: Observable<Payload>;

export const retried$: Observable<Payload> = source$.pipe(
  retry({
    count: 2,
    delay: (): Observable<number> => timer(500),
  })
);
```

`count: 2` plus the fixed `delay` maps cleanly onto the original's 2-attempt, 500 ms spacing.

`retry({ resetOnSuccess: true })` tells RxJS to refill the retry budget whenever a value is emitted â€” useful for long-lived streams that occasionally fail but shouldn't eventually exhaust after N cumulative errors.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface StreamEvent {
  seq: number;
  data: string;
}

declare const source$: Observable<StreamEvent>;

export const longLived$: Observable<StreamEvent> = source$.pipe(
  retry({
    count: 5,
    resetOnSuccess: true,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(2 ** attempt * 200),
  })
);
```

Every successful emission resets the attempt counter, so a stream that emits 100 events between occasional failures doesn't die on the 6th cumulative error.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Row {
  id: number;
  name: string;
}

declare function query$(sql: string): Observable<ReadonlyArray<Row>>;

export const users$: Observable<ReadonlyArray<Row>> = query$("SELECT id, name FROM users").pipe(
  retry({
    count: 1,
    delay: (): Observable<number> => timer(100),
  })
);
```

`count: 1` means a single retry after the first failure. Great for catching a transient pool-exhausted blip without masking real errors.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Blob {
  bytes: Uint8Array;
}

declare const source$: Observable<Blob>;

export const retried$: Observable<Blob> = source$.pipe(
  retry({
    count: 3,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(2 ** attempt * 150),
  })
);
```

`.retry(3)` by itself is instantaneous (and rarely what you want); the object form lets `delay` space retries out with an exponential curve.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface KafkaRecord {
  topic: string;
  key: string;
  value: string;
}

interface ProduceReceipt {
  partition: number;
  offset: bigint;
}

declare function produce$(rec: KafkaRecord): Observable<ProduceReceipt>;

export function publish$(rec: KafkaRecord): Observable<ProduceReceipt> {
  return produce$(rec).pipe(
    retry({
      count: 5,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(2 ** attempt * 250),
    })
  );
}
```

Kafka transient errors (leader not available, broker rebalancing) are exactly the kind that a modest exponential backoff clears within a second or two.

```ts
import { MonoTypeOperatorFunction, Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface BackoffPolicy {
  readonly count: number;
  readonly baseMs: number;
  readonly capMs: number;
}

const DEFAULT_POLICY: BackoffPolicy = { count: 5, baseMs: 300, capMs: 10_000 };

export function withBackoff<T>(
  policy: BackoffPolicy = DEFAULT_POLICY
): MonoTypeOperatorFunction<T> {
  return (src$: Observable<T>): Observable<T> =>
    src$.pipe(
      retry({
        count: policy.count,
        delay: (_err: unknown, attempt: number): Observable<number> =>
          timer(Math.min(2 ** attempt * policy.baseMs, policy.capMs)),
      })
    );
}

declare const source$: Observable<string>;
export const reliable$: Observable<string> = source$.pipe(withBackoff<string>());
```

The `BackoffPolicy` type is a ReadOnly record so callers can't mutate it after passing it in.

A thundering herd is many clients retrying in lockstep after a shared failure â€” they hit the recovering server simultaneously and knock it over again. Exponential backoff (plus jitter) decorrelates retry attempts across clients so the load spreads out.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Task {
  id: string;
}

interface TaskResult {
  id: string;
  ok: boolean;
}

declare function runTask$(t: Task): Observable<TaskResult>;

export function runTaskResilient$(t: Task): Observable<TaskResult> {
  return runTask$(t).pipe(
    retry({
      count: 6,
      delay: (_err: unknown, attempt: number): Observable<number> => {
        const ceiling: number = Math.min(2 ** attempt * 200, 15_000);
        const jittered: number = Math.floor(Math.random() * ceiling);
        return timer(jittered);
      },
    })
  );
}
```

Full jitter (random between 0 and the exponential ceiling) is AWS's recommended pattern â€” the `Math.random()` call spreads the retries.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface S3Put {
  bucket: string;
  key: string;
  body: Uint8Array;
}

interface PutResult {
  etag: string;
}

declare function putObject$(p: S3Put): Observable<PutResult>;

const BUDGET_MS = 20_000;

export function uploadResilient$(p: S3Put): Observable<PutResult> {
  let elapsed = 0;
  return putObject$(p).pipe(
    retry({
      count: Infinity,
      delay: (err: unknown, attempt: number): Observable<number> => {
        const wait: number = 2 ** attempt * 250;
        if (elapsed + wait > BUDGET_MS) {
          return throwError(() => err) as unknown as Observable<number>;
        }
        elapsed += wait;
        return timer(wait);
      },
    })
  );
}
```

The closure-tracked `elapsed` counter enforces a total budget even though `count` is infinite â€” once the cumulative wait would exceed 20 s, the error propagates.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface MqttMessage {
  topic: string;
  payload: Uint8Array;
  qos: 0 | 1 | 2;
}

declare function connectMqtt$(url: string): Observable<MqttMessage>;

export function mqttStream$(url: string): Observable<MqttMessage> {
  return connectMqtt$(url).pipe(
    retry({
      count: Infinity,
      resetOnSuccess: true,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(Math.min(2 ** attempt * 500, 60_000)),
    })
  );
}
```

`resetOnSuccess: true` plus `count: Infinity` is the idiomatic shape for a long-lived broker connection that should reconnect forever but only accumulate "attempts" between successful message windows.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface Frame {
  seq: number;
}

declare const source$: Observable<Frame>;

export const upgraded$: Observable<Frame> = source$.pipe(
  retry({
    count: 2,
    delay: (err: unknown, attempt: number): Observable<number> =>
      attempt < 2
        ? timer(attempt * 300)
        : (throwError(() => err) as unknown as Observable<number>),
  })
);
```

The v6 snippet used `concatMap` and its index to both count and delay; the v7 `delay` callback receives the attempt number directly, so the bookkeeping disappears.

`retryWhen` is deprecated in v7. Rewrite with `retry({ delay })`.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Evt {
  name: string;
}

declare const source$: Observable<Evt>;

export const retried$: Observable<Evt> = source$.pipe(
  retry({
    count: Infinity,
    delay: (): Observable<number> => timer(500),
  })
);
```

The original `retryWhen` snippet had no retry cap â€” it resubscribed forever. `count: Infinity` preserves that semantics; in production you almost always want a finite cap.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface Payload {
  id: string;
}

interface RateLimitError {
  status: 429;
  retryAfterMs: number;
}

function is429(err: unknown): err is RateLimitError {
  return typeof err === "object" && err !== null && (err as RateLimitError).status === 429;
}

declare const source$: Observable<Payload>;

export const throttled$: Observable<Payload> = source$.pipe(
  retry({
    count: 3,
    delay: (err: unknown): Observable<number> =>
      is429(err)
        ? timer(err.retryAfterMs)
        : (throwError(() => err) as unknown as Observable<number>),
  })
);
```

The server's `Retry-After` header tells you exactly how long to wait â€” honouring it is cheaper than guessing with exponential backoff.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Ping {
  ok: boolean;
}

declare const ping$: Observable<Ping>;

export const forever$: Observable<Ping> = ping$.pipe(
  retry({
    count: Infinity,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(Math.min(2 ** attempt * 1000, 60_000)),
  })
);
```

The `Math.min` caps the delay at 60 000 ms â€” otherwise the 20th attempt would sleep for over 12 days.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Q {
  text: string;
}

declare const source$: Observable<Q>;

export const backoffed$: Observable<Q> = source$.pipe(
  retry({
    count: Infinity,
    delay: (_err: unknown, attempt: number): Observable<number> =>
      timer(Math.pow(2, attempt) * 100),
  })
);
```

The `attempt` argument to `delay` plays exactly the role that `i` played inside the `retryWhen` / `delayWhen` pair.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface RedisValue {
  key: string;
  value: string | null;
}

declare function redisGet$(key: string): Observable<RedisValue>;

export function cacheGet$(key: string): Observable<RedisValue> {
  return redisGet$(key).pipe(
    retry({
      count: 3,
      delay: (_err: unknown, attempt: number): Observable<number> =>
        timer(2 ** attempt * 50),
